            </form>
            <p className={`newsletter-footer-text ${isDarkMode ? 'dark-mode' : ''}`}>
              No spam. Unsubscribe at any time. Privacy protected.
            </p>
          </div>
        </section>

      </div>
    </div>
  );
};

