import React from 'react';
import { useNavigate } from 'react-router-dom';

function BlogCard({
  id,
  tag,
  title,
  date,
  readTime,
  delay = 0,
  image,
  summary,
  author,
  keyTakeaways,
  content,
  linkTo
}) {
  const navigate = useNavigate();

  // Function to generate slug from title
  const generateSlug = (title) => {
    return title
      .toLowerCase()
      .replace(/[^\w\s]/g, '')
      .replace(/\s+/g, '-')
      .replace(/-+/g, '-')
      .replace(/^-|-$/g, '');
  };

  const handleReadMore = (e) => {
    e.preventDefault();

    // If linkTo is provided, navigate there instead
    if (linkTo) {
      navigate(linkTo);
      window.scrollTo(0, 0);
      return;
    }

    // Define which tags are News vs Blogs
    const newsTags = ["Platform Updates", "System Architecture", "Data Analytics", "Newsletter"];
    const slug = generateSlug(title);

    // Generate the correct URL based on tag
    if (newsTags.includes(tag)) {
      navigate(`/news/${slug}`, {
        state: {
          id: id,
          tag: tag,
          title: title,
          date: date,
          readTime: readTime,
          summary: summary || `Summary for ${title}`,
          author: author || 'TMC Foodhub Editorial Team',
          keyTakeaways: keyTakeaways || [
            'Data-driven selection reduces hiring risk',
            'Internal resource mobility optimizes efficiency',
            'Agile resourcing allows for faster project pivots'
          ],
          content: content || `<p>Content for ${title}</p>`,
          tags: [tag]
        }
      });
    } else {
      navigate(`/blogs/${slug}`, {
        state: {
          id: id,
          tag: tag,
          title: title,
          date: date,
          readTime: readTime,
          summary: summary || `Summary for ${title}`,
          author: author || 'TMC Foodhub Editorial Team',
          keyTakeaways: keyTakeaways || [
            'Data-driven selection reduces hiring risk',
            'Internal resource mobility optimizes efficiency',
            'Agile resourcing allows for faster project pivots'
          ],
          content: content || `<p>Content for ${title}</p>`,
          tags: [tag]
        }
      });
    }
  };

  return (
    <div
      className="col-lg-4 col-md-6"
      data-aos="fade-up"
      data-aos-delay={`${delay}`}
    >
      <div className="blog-card rounded-4 d-flex flex-column shadow-sm">

        {/* Category Tag */}
        <div className="mb-3">
          <span className="blog-tag">{tag}</span>
        </div>

        {/* Title */}
        <h3 className="blog-title mb-3">{title}</h3>

        {/* Meta Information */}
        <div className="blog-meta mb-auto text-muted small">
          {date} ΓÇó {readTime}
        </div>

        {/* Read More Link */}
        <div className="border-top-light">
          <a
            href="#"
            className="special-link d-inline-flex gap-2 align-items-center text-decoration-none"
            onClick={handleReadMore}
          >
            <span className="icons">
              <i className="icon-1 bi bi-arrow-right-short"></i>
              <i className="icon-2 bi bi-arrow-right-short"></i>
            </span>
            <span>Read more</span>
          </a>
        </div>

      </div>
    </div>
  );
}

export default BlogCard;

import { createContext, useReducer, useCallback, useMemo } from 'react';

export const CartContext = createContext();

const cartReducer = (state, action) => {
  switch (action.type) {
    case 'ADD_ITEM': {
      const existing = state.find(item => item.id === action.payload.id);
      if (existing) {
        return state.map(item =>
          item.id === action.payload.id
            ? { ...item, quantity: item.quantity + 1 }
            : item
        );
      }
      return [...state, { ...action.payload, quantity: 1 }];
    }
    case 'REMOVE_ITEM':
      return state.filter(item => item.id !== action.payload);
    case 'INCREMENT':
      return state.map(item =>
        item.id === action.payload
          ? { ...item, quantity: item.quantity + 1 }
          : item
      );
    case 'DECREMENT':
      return state.map(item =>
        item.id === action.payload
          ? { ...item, quantity: Math.max(1, item.quantity - 1) }
          : item
      );
    case 'CLEAR_CART':
      return [];
    default:
      return state;
  }
};

export function CartProvider({ children }) {
  const [cartItems, dispatch] = useReducer(cartReducer, []);

  const addToCart = useCallback((item) => {
    dispatch({ type: 'ADD_ITEM', payload: { id: item.id, title: item.title, image: item.image, price: item.price } });
  }, []);

  const removeFromCart = useCallback((id) => {
    dispatch({ type: 'REMOVE_ITEM', payload: id });
  }, []);

  const increment = useCallback((id) => {
    dispatch({ type: 'INCREMENT', payload: id });
  }, []);

  const decrement = useCallback((id) => {
    dispatch({ type: 'DECREMENT', payload: id });
  }, []);

  const clearCart = useCallback(() => {
    dispatch({ type: 'CLEAR_CART' });
  }, []);

  const cartCount = useMemo(() => cartItems.reduce((sum, item) => sum + item.quantity, 0), [cartItems]);
  const cartSubtotal = useMemo(() => cartItems.reduce((sum, item) => sum + item.price * item.quantity, 0), [cartItems]);

  const value = useMemo(() => ({
    cartItems,
    cartCount,
    cartSubtotal,
    addToCart,
    removeFromCart,
    increment,
    decrement,
    clearCart
  }), [cartItems, cartCount, cartSubtotal, addToCart, removeFromCart, increment, decrement, clearCart]);

  return (
    <CartContext.Provider value={value}>
      {children}
    </CartContext.Provider>
  );
}

/**
 * Reusable form input field with optional label and validation support.
 */
function Input({
  id,
  label,
  type = "text",
  name,
  placeholder,
  required = false,
  className = "",
  ref = null,
  onChangeFunc = (e) => {},
  ...props
}) {
  return (
    <div className={`form-group ${className}`}>
      {label && <label className="mb-2" htmlFor={id}>{label}</label>}
      <input
        className="form-control"
        id={id}
        type={type}
        name={name}
        placeholder={placeholder}
        required={required}
        ref={ref}
        {...props}
        onChange={(e) => onChangeFunc(e)}
      />
    </div>
  );
}

export default Input;

import React, { createContext, useState, useEffect } from 'react';

export const ThemeContext = createContext();

export const ThemeProvider = ({ children }) => {
  const [isDarkMode, setIsDarkMode] = useState(() => {
    return localStorage.getItem('theme') === 'dark';
  });

  const toggleTheme = () => setIsDarkMode(prev => !prev);

  useEffect(() => {
    const root = document.documentElement;
    if (isDarkMode) {
      root.classList.add('dark-mode');
      root.setAttribute('data-bs-theme', 'dark');
      localStorage.setItem('theme', 'dark');
    } else {
      root.classList.remove('dark-mode');
      root.setAttribute('data-bs-theme', 'light');
      localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);

  return (
    <ThemeContext.Provider value={{ isDarkMode, toggleTheme }}>
      {children}
    </ThemeContext.Provider>
  );
};

