import React, { createContext, useContext, useState, useEffect } from 'react';
import api from '../api/axios';

const AuthContext = createContext(null);

export function AuthProvider({ children }) {
    const [user, setUser] = useState(null);
    const [token, setToken] = useState(localStorage.getItem('auth_token'));
    const [loading, setLoading] = useState(true);

    // On mount, if we have a stored token, validate it by fetching the user
    useEffect(() => {
        if (token) {
            api.get('/user')
                .then((res) => {
                    setUser(res.data);
                })
                .catch(() => {
                    // Token is invalid/expired
                    setToken(null);
                    setUser(null);
                    localStorage.removeItem('auth_token');
                    localStorage.removeItem('auth_user');
                })
                .finally(() => setLoading(false));
        } else {
            setLoading(false);
        }
    }, []);

    const login = async (email, password) => {
        const res = await api.post('/login', { email, password });
        const { user: userData, token: newToken } = res.data;

        setToken(newToken);
        setUser(userData);
        localStorage.setItem('auth_token', newToken);
        localStorage.setItem('auth_user', JSON.stringify(userData));

        return userData;
    };

    const register = async (formData) => {
        const res = await api.post('/register', formData);
        return res.data;
    };

    const sendOtp = async (email) => {
        const res = await api.post('/send-otp', { email });
        return res.data;
    };

    const verifyOtp = async (email, otp) => {
        const res = await api.post('/verify-otp', { email, otp });
        return res.data;
    };

    const logout = async () => {
        try {
            await api.post('/logout');
        } catch {
            // Even if the API call fails, clear local state
        }
        setToken(null);
        setUser(null);
        localStorage.removeItem('auth_token');
        localStorage.removeItem('auth_user');
    };

    const value = {
        user,
        token,
        loading,
        isAuthenticated: !!user,
        login,
        register,
        sendOtp,
        verifyOtp,
        logout,
    };

    return (
        <AuthContext.Provider value={value}>
            {children}
        </AuthContext.Provider>
    );
}

export function useAuth() {
    const context = useContext(AuthContext);
    if (!context) {
        throw new Error('useAuth must be used within an AuthProvider');
    }
    return context;
}

export default AuthContext;

import { createContext, useContext, useReducer, useCallback, useMemo } from 'react';

export const OrderContext = createContext();

const STORAGE_KEY = 'tmcOrders';

function loadOrders() {
    try {
        const saved = localStorage.getItem(STORAGE_KEY);
        return saved ? JSON.parse(saved) : [];
    } catch { return []; }
}

function persist(orders) {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(orders));
}

const orderReducer = (state, action) => {
    let next;
    switch (action.type) {
        case 'PLACE_ORDER':
            next = [action.payload, ...state];
            persist(next);
            return next;
        case 'UPDATE_STATUS':
            next = state.map(o => o.id === action.payload.id ? { ...o, status: action.payload.status } : o);
            persist(next);
            return next;
        case 'CANCEL_ORDER':
            next = state.map(o => o.id === action.payload ? { ...o, status: 'Cancelled' } : o);
            persist(next);
            return next;
        default:
            return state;
    }
};

export function OrderProvider({ children }) {
    const [orders, dispatch] = useReducer(orderReducer, null, loadOrders);

    const placeOrder = useCallback((orderData) => {
        const order = {
            id: `TMC-${Date.now().toString().slice(-5)}`,
            ...orderData,
            status: 'Order Placed',
            placedAt: new Date().toISOString(),
            timeline: [
                { label: 'Order Placed', time: new Date().toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit' }), description: 'Waiting for restaurant confirmation', state: 'completed' },
                { label: 'Order Confirmed', time: '', description: 'Restaurant is preparing your food', state: 'pending' },
                { label: 'Being Prepared', time: '', description: 'Your meal is being cooked', state: 'pending' },
                { label: 'Picked Up', time: '', description: 'Your rider is on the way', state: 'pending' },
                { label: 'Delivered', time: '', description: 'Order delivered', state: 'pending' },
            ],
            rider: {
                name: 'Ricardo Gomez',
                vehicle: 'Honda PCX',
                plate: `NY-${Math.floor(1000 + Math.random() * 9000)}`,
                rating: 4.8,
            },
            estimatedArrival: Math.floor(15 + Math.random() * 20),
        };
        dispatch({ type: 'PLACE_ORDER', payload: order });
        return order;
    }, []);

    const cancelOrder = useCallback((id) => {
        dispatch({ type: 'CANCEL_ORDER', payload: id });
    }, []);

    const activeOrders = useMemo(() => orders.filter(o => !['Delivered', 'Cancelled'].includes(o.status)), [orders]);
    const completedOrders = useMemo(() => orders.filter(o => o.status === 'Delivered'), [orders]);
    const cancelledOrders = useMemo(() => orders.filter(o => o.status === 'Cancelled'), [orders]);

    const value = useMemo(() => ({
        orders, activeOrders, completedOrders, cancelledOrders, placeOrder, cancelOrder
    }), [orders, activeOrders, completedOrders, cancelledOrders, placeOrder, cancelOrder]);

    return (
        <OrderContext.Provider value={value}>
            {children}
        </OrderContext.Provider>
    );
}

export function useOrders() {
    return useContext(OrderContext);
}

import React, { createContext, useContext, useState, useEffect } from 'react';
import { ownerCredentials, getStores, saveStores } from '../data/storesData';

const OwnerAuthContext = createContext(null);

export function OwnerAuthProvider({ children }) {
    const [currentOwner, setCurrentOwner] = useState(() => {
        try { return JSON.parse(localStorage.getItem('tmcOwner')) || null; }
        catch { return null; }
    });

    // stores state ΓÇö seeded from localStorage or defaults
    const [stores, setStores] = useState(() => getStores());

    // Persist owner to localStorage whenever it changes
    useEffect(() => {
        if (currentOwner) localStorage.setItem('tmcOwner', JSON.stringify(currentOwner));
        else localStorage.removeItem('tmcOwner');
    }, [currentOwner]);

    // Persist stores whenever they change
    useEffect(() => { saveStores(stores); }, [stores]);

    function login(email, password) {
        const cred = ownerCredentials.find(
            c => c.email === email.trim() && c.password === password
        );
        if (!cred) return { success: false, message: 'Invalid email or password.' };
        const store = stores.find(s => s.id === cred.storeId);
        setCurrentOwner({ storeId: cred.storeId, email: cred.email, storeName: store?.name });
        return { success: true };
    }

    function logout() { setCurrentOwner(null); }

    // Get the store this owner manages
    const ownerStore = currentOwner ? stores.find(s => s.id === currentOwner.storeId) : null;

    // Update only this owner's store
    function updateStore(updatedStore) {
        setStores(prev => prev.map(s => s.id === updatedStore.id ? updatedStore : s));
    }

    return (
        <OwnerAuthContext.Provider value={{ currentOwner, ownerStore, login, logout, updateStore, stores }}>
            {children}
        </OwnerAuthContext.Provider>
    );
}

export function useOwnerAuth() { return useContext(OwnerAuthContext); }

