import { useEffect, useState, useRef, useLayoutEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { navigationItems } from '../constants/navigation';

export const useNavbarLogic = (isDarkMode) => {
  const [activeSection, setActiveSection] = useState('home');
  const [isScrolled, setIsScrolled] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();  
  
  const isClickScrolling = useRef(false);
  const scrollTimeout = useRef(null);

  // Theme Logic
  useEffect(() => {
    const theme = isDarkMode ? 'dark' : 'light';
    document.documentElement.setAttribute('data-bs-theme', theme);
  }, [isDarkMode]);

  // Scroll Header Style
  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

   useLayoutEffect(() => {
    if (!location.hash) {
      window.scrollTo({ top: 0, left: 0, behavior: 'instant' });
    }
  }, [location.pathname]);

   useEffect(() => {
    if (location.pathname === '/' && location.hash) {
      const sectionId = location.hash.replace('#', '');
      isClickScrolling.current = true;
      setActiveSection(sectionId);

      const timeout = setTimeout(() => {
        const element = document.getElementById(sectionId);
        if (element) {
          const yOffset = -80;
          const y = element.getBoundingClientRect().top + window.pageYOffset + yOffset;
          window.scrollTo({ top: y, behavior: 'smooth' });
        }
        
        if (scrollTimeout.current) clearTimeout(scrollTimeout.current);
        scrollTimeout.current = setTimeout(() => {
          isClickScrolling.current = false;
        }, 1200);
      }, 150);
      return () => clearTimeout(timeout);
    } else if (location.pathname === '/news-and-blogs') {
      setActiveSection('news-blogs');
    }
  }, [location.pathname, location.hash]);

   useEffect(() => {
    if (location.pathname !== '/') return;

    const elementsToObserve = navigationItems
      .flatMap((item) => (item.children ? item.children.map((child) => child.id) : item.id))
      .map((id) => document.getElementById(id))
      .filter(Boolean);

    const observer = new IntersectionObserver(
      (entries) => {
        if (isClickScrolling.current) return;
        
        const visible = entries.find((entry) => entry.isIntersecting);
        if (visible) {
          setActiveSection(visible.target.id);
        }
      },
      { rootMargin: '-30% 0px -40% 0px', threshold: 0.1 }
    );

    elementsToObserve.forEach((el) => observer.observe(el));
    return () => observer.disconnect();
  }, [location.pathname]);

   const isActive = (sectionId) => {
    const isNewsPath = location.pathname === '/news-and-blogs';
    
     if (isNewsPath) {
      return sectionId === 'news-blogs' || sectionId === 'resources-dropdown';
    }

    
    return activeSection === sectionId;
  };

  
  const handleNavClick = (sectionId, e) => {
    if (e) e.preventDefault();
    
    isClickScrolling.current = true;
    setActiveSection(sectionId);
 
    const newPath = sectionId === 'home' ? '/' : `/#${sectionId}`;
    navigate(newPath, { replace: true });

    if (sectionId === 'home') {
    
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else {
      const element = document.getElementById(sectionId);
      if (element) {
        const yOffset = -80;
        const y = element.getBoundingClientRect().top + window.pageYOffset + yOffset;
        window.scrollTo({ top: y, behavior: 'smooth' });
      }
    }

    if (scrollTimeout.current) clearTimeout(scrollTimeout.current);
    scrollTimeout.current = setTimeout(() => {
      isClickScrolling.current = false;
    }, 1000);  
  };

  return { isScrolled, isActive, handleNavClick };
};

import { useState, useRef, useEffect } from "react";

export function getApiUrl() {
  if (typeof import.meta !== "undefined" && import.meta.env && import.meta.env.VITE_API_URL)
    return import.meta.env.VITE_API_URL;
  if (typeof process !== "undefined" && process.env && process.env.API_URL)
    return process.env.API_URL;
  return "http://localhost:8000";
}

export const useSupportPageLogic = () => {
  const [file, setFile] = useState(null);
  const fileInputRef = useRef(null);

  // Topics from backend (for Subject dropdown)
  const [topics, setTopics] = useState([]);
  const [topicsLoading, setTopicsLoading] = useState(true);
  const [topicsError, setTopicsError] = useState(null);

  // Form state
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    topic_id: "",
    message: "",
  });

  // Error state
  const [errors, setErrors] = useState({});

  // Fetch topics on mount
  useEffect(() => {
    let cancelled = false;
    const fetchTopics = async () => {
      try {
        setTopicsLoading(true);
        setTopicsError(null);
        const response = await fetch(`${getApiUrl()}/api/support/topics`);
        if (!response.ok) throw new Error("Failed to load topics");
        const data = await response.json();
        // Support both { data: [...] } and raw array
        const list = Array.isArray(data) ? data : data?.data ?? [];
        if (!cancelled) setTopics(list);
      } catch (err) {
        if (!cancelled) {
          setTopicsError(err.message || "Could not load topics");
          setTopics([]);
        }
      } finally {
        if (!cancelled) setTopicsLoading(false);
      }
    };
    fetchTopics();
    return () => { cancelled = true; };
  }, []);

  // File handlers
  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    if (selectedFile) setFile(selectedFile);
  };

  const handleFileClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileDrop = (e) => {
    e.preventDefault();
    const droppedFile = e.dataTransfer.files[0];
    if (droppedFile) setFile(droppedFile);
  };

  const handleDragOver = (e) => e.preventDefault();
  const removeFile = () => setFile(null);

  // Validation helpers
  const validateName = (name) => /^[A-Za-z\s]+$/.test(name);
 const validateEmail = (email) =>
  /^[A-Za-z0-9._-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}$/.test(email);


  // Form field change handler with real-time sanitization
  const handleChange = (e) => {
    const { name, value } = e.target;
    let sanitizedValue = value;

    // Sanitize email input in real-time
    if (name === "email") {
      // Remove unsafe characters commonly used in XSS/SQL injection
      sanitizedValue = value.replace(/[<>"'();\\\/]/g, "");
    }

    // Update formData
    setFormData((prev) => ({ ...prev, [name]: sanitizedValue }));

    // Validate field
    let error = "";
    if (name === "name" && !/^[A-Za-z\s]*$/.test(sanitizedValue)) {
      error = "Name can only contain letters";
    }
    if (name === "email" && !validateEmail(sanitizedValue)) {
      error = "Invalid email or unsafe characters detected";
    }

    setErrors((prev) => ({ ...prev, [name]: error }));
  };

  // Submit handler
  const handleSubmit = async (e) => {
    e.preventDefault();

    const newErrors = {};
    if (!validateName(formData.name))
      newErrors.name = "Name can only contain letters and spaces";
    if (!validateEmail(formData.email))
      newErrors.email = "Invalid email";
    if (!formData.topic_id)
      newErrors.topic_id = "Please select a topic";

    if (Object.keys(newErrors).length) {
      setErrors(newErrors);
      return;
    }

    try {
      const formPayload = new FormData();
      formPayload.append("name", formData.name);
      formPayload.append("email", formData.email);
      formPayload.append("topic_id", formData.topic_id);
      formPayload.append("message", formData.message);

      if (file) {
        formPayload.append("attachment", file);
      }

      const response = await fetch(
        `${getApiUrl()}/api/support`,
        {
          method: "POST",
          body: formPayload,
        }
      );

      const data = await response.json();

      if (!response.ok) {
        const message = data.message || data.errors ? JSON.stringify(data.errors) : "Submission failed";
        throw new Error(message);
      }

      alert("Support request submitted successfully!");
      setFormData({ name: "", email: "", topic_id: "", message: "" });
      setFile(null);
      setErrors({});
    } catch (error) {
      console.error(error);
      alert(error.message || "Something went wrong.");
    }
  };

  return {
    file,
    fileInputRef,
    formData,
    errors,
    topics,
    topicsLoading,
    topicsError,
    handleChange,
    handleFileChange,
    handleFileClick,
    handleFileDrop,
    handleDragOver,
    removeFile,
    handleSubmit,
  };
};

