                                                        </div>
                                                        <div>
                                                            <p className={styles.reviewUserName}>{review.name}</p>
                                                            <span className={styles.reviewTime}>{review.date}</span>
                                                        </div>
                                                    </div>
                                                    <div className={styles.reviewStars}>
                                                        <StarRow rating={review.rating} size={14} />
