                                            </div>
                                            <p className={styles.cardDesc}>{similar.cuisine.split(', ').join(' ΓÇó ')}</p>
                                            <div className={styles.cardMeta}>
                                                <span className={styles.metaText} style={{ fontWeight: '700' }}>Γé▒85</span>
                                                <span className={styles.metaDot} style={{ color: '#ccc', margin: '0 4px' }}>ΓÇó</span>
                                                <Clock size={12} className={styles.metaIcon} style={{ marginRight: '4px' }} />
